code.C:
#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long x, y;
        scanf("%lld %lld", &x, &y);
        long long z = x;
        while (z % y != 0) {
            z++;
            if (z > 1e18) {
                printf("-1\n");
                break;
            }
        }
        if (z <= 1e18) {
            printf("%lld\n", z);
        }
    }
    return 0;
}

