code.Java:
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long x = sc.nextLong();
            long y = sc.nextLong();
            long z = x;
            while (z % y != 0) {
                z++;
                if (z > 1e18) {
                    System.out.println(-1);
                    break;
                }
            }
            if (z <= 1e18) {
                System.out.println(z);
            }
        }
    }
}

